#version 300 es
uniform mat4 u_MVP;
in vec3 a_Position;
in vec3 a_Color;
out vec3 v_Color;
void main() {
    gl_Position = u_MVP * vec4(a_Position, 1.0);
    v_Color = a_Color;
}

#version 300 es
precision highp float;
in vec3 v_Color;
out vec4 fragColor;
void main() {
    fragColor = vec4(v_Color, 1.0);
}
